```tsx
const [selectedYear, setSelectedYear] = useState<number>(new Date().getFullYear());
    const [hoveredMonth, setHoveredMonth] = useState<number | null>(null);

    const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setSelectedYear(parseInt(e.target.value));
    };

    const monthlyData = useMemo(() => {
        const data: { [key: string]: { [disease: string]: number } } = {};
        patients.forEach((patient) => {
            patient.diseases.forEach((disease) => {
                const date = new Date(disease.date);
                const year = date.getFullYear();
                const month = date.getMonth();

                if (year === selectedYear) {
                    const key = `${year}-${month}`;
                    if (!data[key]) {
                        data[key] = { [disease.name]: 0 };
                    }
                    data[key][disease.name] = (data[key][disease.name] || 0) + 1;
                }
            });
        });
        return data;
    }, [patients, selectedYear]);

    const stds = useMemo(() => {
        const stdSet = new Set<string>();
        patients.forEach((patient) => {
            patient.diseases.forEach((disease) => {
                stdSet.add(disease.name);
            });
        });
        return Array.from(stdSet);
    }, [patients]);
    const maxCount = useMemo(() => {
        let max = 0;
        Object.values(monthlyData).forEach((diseaseData) => {
            Object.values(diseaseData).forEach((count) => {
                if (count > max) {
                    max = count;
                }
            });
        });
        return max;
    }, [monthlyData]);
    const getPath = (disease: string) => {
        const path: string[] = [];
        const monthlyDataEntries = Object.entries(monthlyData);

        monthlyDataEntries.sort((a, b) => {
            const [yearA, monthA] = a[0].split('-').map(Number);
            const [yearB, monthB] = b[0].split('-').map(Number);

            return new Date(yearA, monthA).getTime() - new Date(yearB, monthB).getTime();
        });

        monthlyDataEntries.forEach(([key, diseaseData], index) => {
            const [year, month] = key.split('-').map(Number);
            const count = diseaseData[disease] || 0;
            const x = (index / (monthlyDataEntries.length - 1 || 1)) * 100;
            const y = (1 - (count / (maxCount || 1))) * 100;

            if (index === 0) {
                path.push(`M${x}% ${y}%`); // Move to the starting point
            } else {
                path.push(`L${x}% ${y}%`); // Line to the next point
            }
        });

        return path.join(' ');
    };
